DISPATCHER_FILE="$ROOT_DIR/core/menu_dispatcher.sh"
ENTRIES_LOAD_FILE="$ROOT_DIR/modules/entries.sh"

fail() {
  echo "::error title=smoke_menu::$*"
  echo "[FAIL] $*"
  exit 1
}

assert_file() {
  file="$1"
  [[ -f "$file" ]] || fail "missing file: $file"
}

assert_contains_fixed() {
  file="$1"
  text="$2"
  desc="$3"
  grep -Fq -- "$text" "$file" || fail "$desc (missing: $text)"
}

assert_contains_regex() {
  file="$1"
  pattern="$2"
  desc="$3"
  grep -Eq "$pattern" "$file" || fail "$desc (pattern: $pattern)"
}

assert_native_contains_fixed() {
  text="$1"
  desc="$2"
  grep -Fq -- "$text" "${LUOPO_APP_MARKET_NATIVE_FILES[@]}" || fail "$desc (missing: $text)"
}

assert_native_contains_regex() {
  pattern="$1"
  desc="$2"
  grep -Eq "$pattern" "${LUOPO_APP_MARKET_NATIVE_FILES[@]}" || fail "$desc (pattern: $pattern)"
}

assert_system_misc_contains_regex() {
  pattern="$1"
  desc="$2"
  grep -Eq "$pattern" "${LUOPO_SYSTEM_TOOLS_MISC_FILES[@]}" || fail "$desc (pattern: $pattern)"
}

assert_not_contains_fixed() {
  file="$1"
  text="$2"
  desc="$3"
  if grep -Fq -- "$text" "$file"; then
    fail "$desc (unexpected: $text)"
  fi
}

