  assert_contains_regex "$LUOPO_SYSTEM_TOOLS_HELPERS_FILE" '^create_user_with_sshkey\(\) \{' "system tools should define native user creation with ssh key helper"
  assert_contains_regex "$LUOPO_SYSTEM_TOOLS_HELPERS_FILE" '^fix_dpkg\(\) \{' "system tools should define native dpkg recovery helper"
  assert_contains_regex "$LUOPO_SYSTEM_TOOLS_HELPERS_FILE" '^luopo_system_tools_write_dns\(\) \{' "system tools should define native dns writer helper"
  assert_contains_regex "$LUOPO_SYSTEM_TOOLS_HELPERS_FILE" '^auto_optimize_dns\(\) \{' "system tools should define native dns optimization helper"
  assert_contains_regex "$LUOPO_SYSTEM_TOOLS_HELPERS_FILE" '^linux_update\(\) \{' "system tools should define native update helper"
  assert_contains_regex "$LUOPO_SYSTEM_TOOLS_HELPERS_FILE" '^linux_clean\(\) \{' "system tools should define native clean helper"
  assert_contains_regex "$LUOPO_SYSTEM_TOOLS_HELPERS_FILE" '^f2b_status\(\) \{' "system tools should define native fail2ban status helper"
  assert_contains_regex "$LUOPO_SYSTEM_TOOLS_HELPERS_FILE" '^f2b_install_sshd\(\) \{' "system tools should define native fail2ban install helper"
  assert_contains_regex "$LUOPO_SYSTEM_TOOLS_HELPERS_FILE" '^luopo_system_tools_fail2ban_status_label\(\) \{' "system tools should define native fail2ban status label helper"
  assert_contains_regex "$LUOPO_SYSTEM_TOOLS_HELPERS_FILE" '^k_info\(\) \{' "system tools should define native z command help"
  assert_contains_regex "$LUOPO_SYSTEM_TOOLS_HELPERS_FILE" '^luopo_system_tools_render_cell\(\) \{' "missing LuoPo system tools render helper"
  assert_contains_regex "$LUOPO_SYSTEM_TOOLS_HELPERS_FILE" '^luopo_system_tools_print_user_table\(\) \{' "missing LuoPo system tools user table helper"

  assert_contains_fixed "$ROOT_DIR/core/menu.sh" 'source "$ROOT_DIR/core/runtime.sh"' "core menu should source shared runtime helpers"
  assert_contains_regex "$ROOT_DIR/core/runtime.sh" '^install\(\) \{' "shared runtime should define install helper"
  assert_contains_regex "$ROOT_DIR/core/runtime.sh" '^remove\(\) \{' "shared runtime should define remove helper"
  assert_contains_regex "$ROOT_DIR/core/runtime.sh" '^send_stats\(\) \{' "shared runtime should define stats helper"
  assert_contains_regex "$ROOT_DIR/core/runtime.sh" '^break_end\(\) \{' "shared runtime should define break helper"
  assert_contains_regex "$ROOT_DIR/core/runtime.sh" '^install_docker\(\) \{' "shared runtime should define docker installer helper"
  assert_contains_regex "$ROOT_DIR/core/runtime.sh" '^tmux_run\(\) \{' "shared runtime should define tmux attach helper"
  assert_contains_regex "$ROOT_DIR/core/runtime.sh" '^tmux_run_d\(\) \{' "shared runtime should define tmux background helper"
  assert_contains_regex "$ROOT_DIR/core/runtime.sh" '^bbr_on\(\) \{' "shared runtime should define bbr helper"
  assert_contains_regex "$ROOT_DIR/core/runtime.sh" '^server_reboot\(\) \{' "shared runtime should define reboot helper"
  assert_contains_regex "$ROOT_DIR/core/runtime.sh" '^add_sshpasswd\(\) \{' "shared runtime should define ssh password helper"
  assert_contains_fixed "$LUOPO_WARP_ACTIONS_FILE" 'bash menu.sh [option] [lisence/url/token]' "warp native command mismatch"
  assert_not_contains_fixed "$INSTALL_FILE" 'K_COMPAT_PATH="/usr/local/bin/k"' "install should not define k compatibility launcher"
  assert_contains_fixed "$INSTALL_FILE" 'rm -f /usr/local/bin/k /usr/bin/k' "install should cleanup legacy k launchers"
  assert_contains_fixed "$INSTALL_FILE" 'REPO_ARCHIVE_URL="${LUOPO_REPO_ARCHIVE_URL:-https://codeload.github.com/LuoPoJunZi/toolkit/tar.gz/refs/heads/main}"' "install should support remote bootstrap archive"
  assert_contains_fixed "$INSTALL_FILE" 'bootstrap_source_tree() {' "install bootstrap function missing"
  assert_contains_fixed "$INSTALL_FILE" 'SOURCE_DIR="$extracted_dir"' "install should switch to downloaded source tree"
  assert_contains_fixed "$INSTALL_FILE" '--exclude="vendor/luopo.sh"' "install should not copy local-only vendor snapshot"
  assert_contains_fixed "$UNINSTALL_FILE" 'rm -f /usr/local/bin/k /usr/bin/k' "uninstall should cleanup legacy k launchers"
  if git ls-files --error-unmatch vendor/luopo.sh >/dev/null 2>&1; then
    fail "vendor/luopo.sh should remain local-only and must not be tracked"
  fi

  echo "[PASS] menu routing smoke checks passed"
}

main "$@"
